  1	import * as React from 'react';
  2	import { isMultiCluster, Paths } from '../../config';
  3	import { Link } from 'react-router-dom-v5-compat';
  4	import { GVKToBadge } from '../VirtualList/Config';
  5	import { PFBadge } from 'components/Pf/PfBadges';
  6	import { Tooltip, TooltipPosition } from '@patternfly/react-core';
  7	import { KialiIcon } from 'config/KialiIcon';
  8	import { kialiStyle } from 'styles/StyleUtils';
  9	import { KialiAppState } from '../../store/Store';
 10	import { connect } from 'react-redux';
 11	import { isParentKiosk, kioskContextMenuAction } from '../Kiosk/KioskActions';
 12	import { GroupVersionKind } from '../../types/IstioObjects';
 13	import { getGVKTypeString, kindToStringIncludeK8s } from '../../utils/IstioConfigUtils';
 14	import { classes } from 'typestyle';
 15	import { infoStyle } from 'styles/IconStyle';
 16	
 17	const objectInfoStyle = kialiStyle({
 18	  marginBottom: '-0.125rem',
 19	  marginRight: '0',
 20	  marginTop: '0'
 21	});
 22	
 23	type ReduxProps = {
 24	  kiosk: string;
 25	};
 26	
 27	type ReferenceIstioObjectProps = {
 28	  cluster?: string;
 29	  name: string;
 30	  namespace: string;
 31	  objectGVK: GroupVersionKind;
 32	  query?: string;
 33	  subType?: string;
 34	};
 35	
 36	type IstioObjectProps = ReduxProps &
 37	  ReferenceIstioObjectProps & {
 38	    children: React.ReactNode;
 39	  };
 40	
 41	export const GetIstioObjectUrl = (
 42	  name: string,
 43	  namespace: string,
 44	  objectGVK: GroupVersionKind,
 45	  cluster?: string,
 46	  query?: string
 47	): string => {
 48	  let to = `/namespaces/${namespace}/${Paths.ISTIO}`;
 49	
 50	  to = `${to}/${objectGVK.Group}/${objectGVK.Version}/${objectGVK.Kind}/${name}`;
 51	
 52	  if (cluster && isMultiCluster) {
 53	    to = `${to}?clusterName=${cluster}`;
 54	  }
 55	
 56	  if (!!query) {
 57	    if (to.includes('?')) {
 58	      to = `${to}&${query}`;
 59	    } else {
 60	      to = `${to}?${query}`;
 61	    }
 62	  }
 63	
 64	  return to;
 65	};
 66	
 67	export const ReferenceIstioObjectLink: React.FC<ReferenceIstioObjectProps> = (props: ReferenceIstioObjectProps) => {
 68	  const { name, namespace, cluster, objectGVK, subType } = props;
 69	  const badge = GVKToBadge[getGVKTypeString(objectGVK)];
 70	
 71	  let showLink = true;
 72	  let showTooltip = false;
 73	  let tooltipMsg: string | undefined = undefined;
 74	  let reference = `${namespace}/${name}`;
 75	
 76	  if (name === 'mesh') {
 77	    reference = name;
 78	    showLink = false;
 79	    showTooltip = true;
 80	    tooltipMsg = 'The reserved word, "mesh", implies all of the sidecars in the mesh';
 81	  }
 82	
 83	  return (
 84	    <>
 85	      <PFBadge badge={badge} position={TooltipPosition.top} />
 86	
 87	      {showLink && (
 88	        <IstioObjectLink name={name} namespace={namespace} cluster={cluster} objectGVK={objectGVK} subType={subType}>
 89	          {reference}
 90	        </IstioObjectLink>
 91	      )}
 92	
 93	      {!showLink && <div style={{ display: 'inline-block' }}>{reference}</div>}
 94	
 95	      {showTooltip && (
 96	        <Tooltip position={TooltipPosition.right} content={<div style={{ textAlign: 'left' }}>{tooltipMsg}</div>}>
 97	          <KialiIcon.Info className={classes(infoStyle, objectInfoStyle)} />
 98	        </Tooltip>
 99	      )}
100	    </>
101	  );
102	};
103	
104	const IstioObjectLinkComponent: React.FC<IstioObjectProps> = (props: IstioObjectProps) => {
105	  const { name, namespace, objectGVK, cluster, query } = props;
106	  const href = GetIstioObjectUrl(name, namespace, objectGVK, cluster, query);
107	
108	  return isParentKiosk(props.kiosk) ? (
109	    <Link
110	      to=""
111	      onClick={() => {
112	        kioskContextMenuAction(href);
113	      }}
114	    >
115	      {props.children}
116	    </Link>
117	  ) : (
118	    // @TODO put cluster in link when all objects have multicluster support
119	    <Link to={href} data-test={`${kindToStringIncludeK8s(objectGVK.Group, objectGVK.Kind)}-${namespace}-${name}`}>
120	      {props.children}
121	    </Link>
122	  );
123	};
124	
125	const mapStateToProps = (state: KialiAppState): ReduxProps => ({
126	  kiosk: state.globalState.kiosk
127	});
128	
129	export const IstioObjectLink = connect(mapStateToProps)(IstioObjectLinkComponent);

